import React from 'react'
import { Button, DialogOverlay, DialogOverlayActions, DialogOverlayFooter, Paragraph } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { setAvailability as setHelperAvailability } from '../services/helperQueue/helperQueueService'

export default function HelperAvailabilityConfirmDialog({ confirmationOverlay, onConfirm }) {
  const [t] = useTranslation()

  const handleConfirmUnavailable = async () => {
    await setHelperAvailability(false)
    confirmationOverlay.close()
    if (onConfirm) {
      onConfirm()
    }
  }

  const handleStayAvailable = () => {
    confirmationOverlay.close()
    if (onConfirm) {
      onConfirm()
    }
  }

  return (
    <DialogOverlay
      title={t('chat.helper-availability-confirm.title', 'Chat Helper Availability')}
      {...confirmationOverlay}
      closeOnClickAway={false}
      nonClosable
    >
      <Paragraph size="sm">
        {t(
          'chat.helper-availability-confirm.message',
          'You are closing Chat. Do you want to remain available to help others?'
        )}
      </Paragraph>
      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Button onClick={handleConfirmUnavailable}>
            {t('chat.helper-availability-confirm.unavailable', 'Set Unavailable')}
          </Button>
          <Button onClick={handleStayAvailable} emphasis="high">
            {t('chat.helper-availability-confirm.stay-available', 'Stay Available')}
          </Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
